#!/usr/bin/env node

import { Command } from 'commander';
import { resolveConfig } from './config.js';
import { registerStatusCommand } from './commands/status.js';
import { registerListCommand } from './commands/list.js';
import { registerClaimCommand } from './commands/claim.js';
import { registerProgressCommand } from './commands/progress.js';
import { registerCompleteCommand } from './commands/complete.js';
import { registerShowCommand } from './commands/show.js';
import { registerMineCommand } from './commands/mine.js';
import { registerBlockCommand } from './commands/block.js';
import { registerUnblockCommand } from './commands/unblock.js';

const __dirname = new URL('.', import.meta.url).pathname;
// Read version from package.json
let version = '0.1.0';
try {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pkg = await import('../package.json', { with: { type: 'json' } });
  version = (pkg.default as Record<string, unknown>)?.version as string ?? version;
} catch {
  // fallback version
}

const program = new Command();

program
  .name('mt-cli')
  .description('Milestone Tracker AI Agent CLI — AI Agent 使用的里程碑跟踪命令行工具')
  .version(version, '-v, --version', '显示版本号')
  .option('--config <path>', '指定配置文件路径');

// Lazy config resolution — only resolve when a command needs it
function getConfig() {
  const opts = program.opts<{ config?: string }>();
  return resolveConfig(opts.config);
}

// Register status command (top-level)
registerStatusCommand(program, getConfig);

// Register tasks subcommand group
const tasks = program
  .command('tasks')
  .description('任务管理命令');

registerListCommand(tasks, getConfig);
registerClaimCommand(tasks, getConfig);
registerProgressCommand(tasks, getConfig);
registerCompleteCommand(tasks, getConfig);
registerShowCommand(tasks, getConfig);
registerMineCommand(tasks, getConfig);
registerBlockCommand(tasks, getConfig);
registerUnblockCommand(tasks, getConfig);

// Parse and execute
program.parse(process.argv);

// ── JSON Output Utilities ───────────────────────────────────────────────────
// Shared formatting for --json flag across all CLI commands.

import { MtCliError } from '../client.js';

// ── Public API ──────────────────────────────────────────────────────────────

export interface JsonErrorShape {
  error: string;
  code: string;
  details?: unknown;
}

/**
 * Write a JSON payload to stdout (pretty-printed, trailing newline).
 */
export function outputJson(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + '\n');
}

/**
 * Format an error as structured JSON, write to stdout, and exit with code 1.
 * Never returns (return type is `never`).
 */
export function outputJsonError(err: unknown): never {
  const payload: JsonErrorShape = {
    error: getErrorMessage(err),
    code: formatErrorCode(err),
  };

  const details = formatErrorDetails(err);
  if (details !== undefined) {
    payload.details = details;
  }

  process.stdout.write(JSON.stringify(payload, null, 2) + '\n');
  process.exit(1);
}

// ── Error Code Mapping ──────────────────────────────────────────────────────

/**
 * Map an error to a machine-readable code string.
 *
 * - MtCliError with HTTP status → `HTTP_${status}` (e.g. `HTTP_404`)
 * - MtCliError with status 0 and abort message → `TIMEOUT`
 * - MtCliError with status 0 and fetch message → `NETWORK_ERROR`
 * - Anything else → `UNKNOWN_ERROR`
 */
export function formatErrorCode(err: unknown): string {
  if (err instanceof MtCliError) {
    if (err.status === 0) {
      // Timeout: abort-related message
      if (err.message.includes('请求超时') || err.message.includes('timeout')) {
        return 'TIMEOUT';
      }
      // Network: fetch-related message
      if (err.message.includes('无法连接') || err.message.includes('fetch')) {
        return 'NETWORK_ERROR';
      }
    }
    if (err.status > 0) {
      return `HTTP_${err.status}`;
    }
  }
  return 'UNKNOWN_ERROR';
}

/**
 * Extract structured details from MtCliError (url, suggestion),
 * or return undefined for unknown error types.
 */
export function formatErrorDetails(err: unknown): unknown {
  if (err instanceof MtCliError) {
    const details: Record<string, string> = {};
    if (err.url) details.url = err.url;
    if (err.suggestion) details.suggestion = err.suggestion;
    if (Object.keys(details).length > 0) return details;
  }
  return undefined;
}

// ── Internal Helpers ────────────────────────────────────────────────────────

function getErrorMessage(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  if (typeof err === 'string') {
    return err;
  }
  return String(err);
}

// ── HTTP Error Messages (Chinese) ────────────────────────────────────────────

const STATUS_MESSAGES: Record<number, string> = {
  400: '请求格式错误，请检查请求参数',
  401: 'API 密钥无效或已过期，请检查 MT_API_KEY 或 .mt-env 配置',
  403: '无权限执行此操作',
  404: '请求的资源不存在，请检查 URL 和 ID',
  409: '操作冲突，资源状态已变更，请刷新后重试',
  422: '请求数据验证失败，请检查字段格式',
  429: '请求过于频繁，请稍后重试',
  500: '服务器内部错误，请联系管理员',
  502: '网关错误，服务器暂时不可用',
  503: '服务暂时不可用，请稍后重试',
};

function getStatusMessage(status: number): string {
  return STATUS_MESSAGES[status] || `未知错误 (HTTP ${status})`;
}

function getSuggestion(status: number): string {
  switch (status) {
    case 400:
    case 422:
      return '[建议] 检查请求参数是否符合 API 规范';
    case 401:
      return '[建议] 重新获取 API 密钥或检查 .mt-cli.json 中的 key 配置';
    case 404:
      return '[建议] 使用 mt-cli status 确认服务器地址和里程碑 ID';
    case 409:
      return '[建议] 先查询最新状态 (mt-cli list)，再尝试操作';
    default:
      return '[建议] 稍后重试，或使用 mt-cli status 检查服务器连通性';
  }
}

// ── Error Class ─────────────────────────────────────────────────────────────

export class MtCliError extends Error {
  constructor(
    public readonly status: number,
    public readonly message: string,
    public readonly suggestion: string,
    public readonly url: string,
  ) {
    super(`[错误] HTTP ${status}: ${message}\n${suggestion}`);
    this.name = 'MtCliError';
  }
}

// ── HTTP Client ─────────────────────────────────────────────────────────────

export interface MtClientOptions {
  baseUrl: string;
  apiKey: string;
  timeoutMs?: number;
}

export class MtClient {
  private baseUrl: string;
  private apiKey: string;
  private timeoutMs: number;

  constructor(opts: MtClientOptions) {
    this.baseUrl = opts.baseUrl.replace(/\/+$/, '');
    this.apiKey = opts.apiKey;
    this.timeoutMs = opts.timeoutMs ?? 10_000;
  }

  private headers(): Record<string, string> {
    return {
      'Authorization': `Bearer ${this.apiKey}`,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };
  }

  async get<T>(path: string): Promise<T> {
    return this.request<T>('GET', path);
  }

  async post<T>(path: string, body?: unknown): Promise<T> {
    return this.request<T>('POST', path, body);
  }

  async patch<T>(path: string, body?: unknown): Promise<T> {
    return this.request<T>('PATCH', path, body);
  }

  private async request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = `${this.baseUrl}${path}`;
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), this.timeoutMs);

    try {
      const response = await fetch(url, {
        method,
        headers: this.headers(),
        body: body !== undefined ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timer);

      // Log request on failure
      if (!response.ok) {
        console.error(`[HTTP] ${method} ${url} → ${response.status}`);
      }

      let data: unknown;
      const text = await response.text();
      try {
        data = JSON.parse(text);
      } catch {
        // Non-JSON response
        if (!response.ok) {
          throw new MtCliError(
            response.status,
            `服务器返回非 JSON 响应: ${text.slice(0, 200)}`,
            getSuggestion(response.status),
            url,
          );
        }
        throw new Error(`[错误] 无法解析服务器响应为 JSON`);
      }

      if (!response.ok) {
        const errData = data as Record<string, unknown>;
        const message =
          (errData['message'] as string) ||
          (errData['error'] as string) ||
          getStatusMessage(response.status);
        throw new MtCliError(response.status, message, getSuggestion(response.status), url);
      }

      return data as T;
    } catch (err) {
      clearTimeout(timer);
      if (err instanceof MtCliError) throw err;
      if (err instanceof DOMException && err.name === 'AbortError') {
        throw new MtCliError(
          0,
          `请求超时 (${this.timeoutMs}ms)，服务器未响应`,
          '[建议] 检查服务器是否运行，或使用 mt-cli status 测试连通性',
          url,
        );
      }
      if (err instanceof TypeError && (err as Error).message.includes('fetch')) {
        throw new MtCliError(
          0,
          `无法连接到服务器: ${(err as Error).message}`,
          '[建议] 检查 serverUrl 配置和服务器运行状态',
          url,
        );
      }
      throw err;
    }
  }
}

import { readFileSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { homedir } from 'node:os';
import { fileURLToPath } from 'node:url';

// ── Types ───────────────────────────────────────────────────────────────────

export interface MtCliConfig {
  serverUrl: string;
  milestoneId: string;
  key?: string;
  agentName?: string;
}

export interface ResolvedConfig extends MtCliConfig {
  apiKey: string;
  configPath: string | null;
}

// ── Helpers ─────────────────────────────────────────────────────────────────

function readJsonFile(filePath: string): Record<string, unknown> | null {
  try {
    if (!existsSync(filePath)) return null;
    const raw = readFileSync(filePath, 'utf-8');
    return JSON.parse(raw) as Record<string, unknown>;
  } catch {
    console.error(`[警告] 配置文件解析失败: ${filePath}，已跳过`);
    return null;
  }
}

function readEnvFile(dir: string): string | null {
  const envPath = join(dir, '.mt-env');
  try {
    if (!existsSync(envPath)) return null;
    const raw = readFileSync(envPath, 'utf-8');
    for (const line of raw.split('\n')) {
      const trimmed = line.trim();
      if (trimmed.startsWith('MT_API_KEY=')) {
        return trimmed.slice('MT_API_KEY='.length).replace(/^["']|["']$/g, '');
      }
    }
    return null;
  } catch {
    return null;
  }
}

// ── Config Resolution ───────────────────────────────────────────────────────

/**
 * Resolve configuration with layered priority:
 * 1. Explicit --config path
 * 2. `.mt-cli.json` in cwd
 * 3. `~/.mt-cli.json` (home directory)
 *
 * API key priority:
 * 1. `MT_API_KEY` environment variable
 * 2. `.mt-env` file in cwd
 * 3. `key` field in config file
 */
export function resolveConfig(configPathOverride?: string): ResolvedConfig {
  let configData: Record<string, unknown> | null = null;
  let usedConfigPath: string | null = null;

  // 1. Try explicit config path
  if (configPathOverride) {
    configData = readJsonFile(configPathOverride);
    if (configData !== null) {
      usedConfigPath = configPathOverride;
    } else {
      console.error(`[错误] 指定的配置文件不存在或格式错误: ${configPathOverride}`);
      process.exit(1);
    }
  }

  // 2. Try cwd .mt-cli.json
  if (configData === null) {
    const cwdConfig = join(process.cwd(), '.mt-cli.json');
    const data = readJsonFile(cwdConfig);
    if (data !== null) {
      configData = data;
      usedConfigPath = cwdConfig;
    }
  }

  // 3. Try ~/.mt-cli.json
  if (configData === null) {
    const homeConfig = join(homedir(), '.mt-cli.json');
    const data = readJsonFile(homeConfig);
    if (data !== null) {
      configData = data;
      usedConfigPath = homeConfig;
    }
  }

  if (configData === null) {
    console.error(
      '[错误] 未找到配置文件。请在项目根目录创建 .mt-cli.json 或在 HOME 目录创建 ~/.mt-cli.json。'
    );
    console.error('[提示] 配置格式: { "serverUrl": "http://localhost:5173", "milestoneId": "MS-1" }');
    process.exit(1);
  }

  // Extract fields with defaults
  const serverUrl = (configData['serverUrl'] as string) || 'http://localhost:5173';
  const milestoneId = configData['milestoneId'] as string;
  const key = configData['key'] as string | undefined;
  const agentName = configData['agentName'] as string | undefined;

  if (!milestoneId) {
    console.error('[错误] 配置文件中缺少必填字段 "milestoneId"。');
    process.exit(1);
  }

  // API key resolution: env → .mt-env file → config key field
  const envKey = process.env['MT_API_KEY'] || null;
  const envFileKey = readEnvFile(process.cwd());
  const apiKey = envKey || envFileKey || key || '';

  if (!apiKey) {
    console.error(
      '[错误] 未找到 API 密钥。请设置环境变量 MT_API_KEY、创建 .mt-env 文件，或在配置文件中添加 "key" 字段。'
    );
    process.exit(1);
  }

  return {
    serverUrl,
    milestoneId,
    key,
    agentName,
    apiKey,
    configPath: usedConfigPath,
  };
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

/** Verification evidence item submitted by an agent. */
export interface EvidenceItem {
  command: string;
  exitCode: number;
  verdict: 'pass' | 'fail';
}

function parseEvidenceJson(raw: string): EvidenceItem[] {
  const parsed = JSON.parse(raw);
  if (!Array.isArray(parsed)) throw new Error('--evidence JSON must be an array');
  return parsed;
}

function parseFilesTouched(raw: string): string[] {
  const parsed = JSON.parse(raw);
  if (!Array.isArray(parsed)) throw new Error('--files-touched JSON must be an array');
  return parsed;
}

export function registerCompleteCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('complete <taskId>')
    .description('完成任务')
    .option('--message <msg>', '完成说明')
    .option('--commit <hash>', '关联的 Git 提交哈希')
    .option('--evidence <json>', '验证证据 JSON 数组')
    .option('--files-touched <json>', '修改的文件列表 JSON 数组')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: {
      message?: string;
      commit?: string;
      evidence?: string;
      filesTouched?: string;
      json?: boolean;
    }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const body: Record<string, unknown> = {};
        if (opts.message) body.progressMessage = opts.message;
        if (opts.commit) body.commitHash = opts.commit;
        if (opts.evidence) body.evidenceJson = parseEvidenceJson(opts.evidence);
        if (opts.filesTouched) body.filesTouched = parseFilesTouched(opts.filesTouched);

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/complete`, body);

        if (opts.json) {
          outputJson(result);
          return;
        }

        console.log(`✓ 已完成 #${result.shortId}「${result.title}」`);
        console.log(`  状态: 已完成`);
        if (result.commitHash) {
          console.log(`  提交: ${result.commitHash}`);
        }
        if (result.progressMessage) {
          console.log(`  说明: ${result.progressMessage}`);
        }
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { statusLabel, taskRow } from '../utils/format.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

export function registerListCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('list')
    .description('列出所有任务（默认排除已完成和已跳过）')
    .option('--status <status>', '按状态筛选 (todo|in-progress|blocked|review|done|skipped)')
    .option('--json', '以 JSON 格式输出')
    .action(async (opts: { status?: string; json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const params = new URLSearchParams({ milestoneId: config.milestoneId });
        // Default filter excludes closed tasks (done, skipped)
        const status = opts.status;
        if (status) {
          params.set('status', status);
        }

        const tasks = await client.get<TaskResponse[]>(`/api/tasks?${params}`);

        if (opts.json) {
          outputJson(tasks);
          return;
        }

        if (tasks.length === 0) {
          console.log(`\n  暂无${status ? `状态为「${statusLabel(status)}」的` : ''}任务。\n`);
          return;
        }

        // Default: exclude done/skipped unless explicitly requested
        const filtered = status
          ? tasks
          : tasks.filter((t) => t.status !== 'done' && t.status !== 'skipped');

        if (filtered.length === 0) {
          console.log('\n  所有任务均已完成或跳过。使用 --status all 查看全部。\n');
          return;
        }

        console.log(`\n  共 ${filtered.length} 个任务:\n`);
        for (const task of filtered) {
          console.log(taskRow(task));
          console.log('');
        }
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { statusLabel, progressBar, formatDate, divider } from '../utils/format.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

/**
 * Resolve #N references in a description string.
 * Replaces each #N with a summary line from the task list.
 */
function resolveDescriptionReferences(
  description: string,
  allTasks: TaskResponse[],
): string {
  return description.replace(/#(\d+)/g, (match, numStr) => {
    const shortId = parseInt(numStr, 10);
    const ref = allTasks.find((t) => t.shortId === shortId);
    if (!ref) {
      return `${match} (引用的任务不存在)`;
    }
    return `${match} [${ref.title}] (${statusLabel(ref.status)})`;
  });
}

export function registerShowCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('show <taskId>')
    .description('查看任务详情')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: { json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        // Fetch task detail
        const task = await client.get<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}`);

        if (opts.json) {
          outputJson(task);
          return;
        }

        // Fetch all tasks for inline reference resolution
        const allTasks = await client.get<TaskResponse[]>(
          `/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`,
        );

        console.log('');
        console.log(divider('═', 40));
        console.log(`  #${task.shortId}  ${task.title}`);
        console.log(divider('═', 40));
        console.log('');
        console.log(`  ID:         ${task.id}`);
        console.log(`  模块:       ${task.moduleId}`);
        console.log(`  状态:       ${statusLabel(task.status)}`);
        console.log(`  负责人:     ${task.assignee || '(未分配)'}`);
        console.log('');

        if (task.subTotal > 0) {
          console.log(`  进度:       ${progressBar(task.subDone, task.subTotal)} (${task.subDone}/${task.subTotal})`);
          console.log('');
        }

        if (task.description) {
          const resolved = resolveDescriptionReferences(task.description, allTasks);
          console.log(divider('─', 40));
          console.log('  描述:');
          console.log('');
          // Indent description lines
          for (const line of resolved.split('\n')) {
            console.log(`    ${line}`);
          }
          console.log('');
        }

        if (task.references) {
          console.log(divider('─', 40));
          console.log(`  引用: ${task.references}`);
          console.log('');
        }

        if (task.progressMessage) {
          console.log(divider('─', 40));
          console.log('  进度说明:');
          console.log(`    ${task.progressMessage}`);
          console.log('');
        }

        if (task.commitHash) {
          console.log(`  Git 提交:   ${task.commitHash}`);
        }

        console.log('');
        console.log(divider('─', 40));
        console.log(`  创建时间:   ${formatDate(task.createdAt)}`);
        console.log(`  更新时间:   ${formatDate(task.updatedAt)}`);
        if (task.reportedAt) {
          console.log(`  报告时间:   ${formatDate(task.reportedAt)}`);
        }
        console.log(divider('═', 40));
        console.log('');
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

// ── Shared Types ────────────────────────────────────────────────────────────

export type TaskStatus = 'todo' | 'in-progress' | 'blocked' | 'review' | 'done' | 'skipped';

export interface TaskResponse {
  id: string;
  shortId: number;
  moduleId: string;
  title: string;
  description: string | null;
  references: string | null;
  status: TaskStatus;
  assignee: string | null;
  subTotal: number;
  subDone: number;
  progressMessage: string | null;
  blockedReason: string | null;
  commitHash: string | null;
  evidenceJson: unknown | null;
  filesTouched: string[] | null;
  createdAt: string;
  updatedAt: string;
  reportedAt: string | null;
}

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getModule, updateModule } from '$lib/server/module-service.js';
import { updateModuleSchema } from '$lib/schemas/index.js';

export const GET: RequestHandler = async ({ params }) => {
	const mod = await getModule(db, params.id);
	if (!mod) {
		return json({ error: 'not_found', message: `Module ${params.id} not found` }, { status: 404 });
	}
	return json(mod);
};

export const PATCH: RequestHandler = async ({ params, request }) => {
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = updateModuleSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	const mod = await updateModule(db, params.id, parsed.data);
	if (!mod) {
		return json({ error: 'not_found', message: `Module ${params.id} not found` }, { status: 404 });
	}
	return json(mod);
};

import { z } from 'zod';
import { moduleStatusEnum } from '../db/schema.js';
import { moduleIdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createModuleSchema = z.object({
	milestoneId: milestoneIdSchema,
	name: z.string().min(1, 'Name is required').max(200, 'Name must be under 200 characters'),
	description: z.string().max(5000).optional(),
	sortOrder: z.number().int().nonnegative().default(0)
});
export type CreateModuleInput = z.infer<typeof createModuleSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateModuleSchema = z.object({
	name: z.string().min(1).max(200).optional(),
	description: z.string().max(5000).optional(),
	status: z.enum(moduleStatusEnum).optional(),
	sortOrder: z.number().int().nonnegative().optional()
});
export type UpdateModuleInput = z.infer<typeof updateModuleSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const moduleResponseSchema = z.object({
	id: moduleIdSchema,
	milestoneId: milestoneIdSchema,
	name: z.string(),
	description: z.string().nullable(),
	status: z.enum(moduleStatusEnum),
	sortOrder: z.number().int()
});
export type ModuleResponse = z.infer<typeof moduleResponseSchema>;

import { eq, asc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, milestones } from '$lib/db/schema.js';
import type { CreateModuleInput, UpdateModuleInput } from '$lib/schemas/index.js';

/** Body data for createModule (milestoneId comes from URL param). */
type CreateModuleBody = Omit<CreateModuleInput, 'milestoneId'>;

// ── ID Generation ────────────────────────────────────────────────────────────

/** Generate MOD-{milestone_seq}-{next_seq} ID. */
export async function nextModuleId(
	db: BetterSQLite3Database<any>,
	milestoneId: string
): Promise<string> {
	const msSeq = milestoneId.replace('MS-', '');
	const rows = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();
	let maxSeq = 0;
	for (const row of rows) {
		// Format: MOD-{msSeq}-{seq}
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MOD-${msSeq}-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createModule(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	data: CreateModuleBody
) {
	// Verify milestone exists
	const ms = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!ms) return null;

	const id = await nextModuleId(db, milestoneId);
	const result = await db
		.insert(modules)
		.values({
			id,
			milestoneId,
			name: data.name,
			description: data.description ?? null,
			sortOrder: data.sortOrder ?? 0
		})
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── Get by ID ─────────────────────────────────────────────────────────────────

export async function getModule(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const row = await db.select().from(modules).where(eq(modules.id, id)).get();
	if (!row) return null;
	return formatModuleResponse(row);
}

// ── List by Milestone ────────────────────────────────────────────────────────

export async function listModulesByMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string
) {
	const rows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();
	return rows.map(formatModuleResponse);
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateModule(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateModuleInput
) {
	const existing = await db.select().from(modules).where(eq(modules.id, id)).get();
	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.name !== undefined) updates.name = data.name;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.status !== undefined) updates.status = data.status;
	if (data.sortOrder !== undefined) updates.sortOrder = data.sortOrder;

	if (Object.keys(updates).length === 0) {
		return formatModuleResponse(existing);
	}

	const result = await db
		.update(modules)
		.set(updates)
		.where(eq(modules.id, id))
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { listModulesByMilestone, createModule } from '$lib/server/module-service.js';
import { createModuleSchema } from '$lib/schemas/index.js';

export const GET: RequestHandler = async ({ params }) => {
	const mods = await listModulesByMilestone(db, params.id);
	return json(mods);
};

export const POST: RequestHandler = async ({ params, request }) => {
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = createModuleSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	const mod = await createModule(db, params.id, {
		name: parsed.data.name,
		description: parsed.data.description,
		sortOrder: parsed.data.sortOrder ?? 0
	});
	if (!mod) {
		return json({ error: 'not_found', message: `Milestone ${params.id} not found` }, { status: 404 });
	}
	return json(mod, { status: 201 });
};

